import{_ as e,o as t,c as n,a3 as a}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"10. Anti Discrimination","description":"","frontmatter":{"title":"10. Anti Discrimination","eba":"Allied Health Professionals 2021-2026","topics":["flexible-work","preliminary","discrimination"]},"headers":[],"relativePath":"ebas/allied-health/preliminary/10-anti-discrimination.md","filePath":"ebas/allied-health/preliminary/10-anti-discrimination.md"}'),r={name:"ebas/allied-health/preliminary/10-anti-discrimination.md"};function o(s,i,l,p,d,c){return t(),n("div",null,[...i[0]||(i[0]=[a('<h1 id="_10-anti-discrimination" tabindex="-1">10. Anti Discrimination <a class="header-anchor" href="#_10-anti-discrimination" aria-label="Permalink to &quot;10. Anti Discrimination&quot;">​</a></h1><p><strong>10.1</strong> Those covered by this Agreement respect and value the diversity of the work force and will help protect Employees against unfair treatment and unlawful discrimination on the basis of race, colour, sex (gender), sexual orientation, age,</p><p>physical or mental disability, marital status, family responsibilities, pregnancy, religion (religious belief or activity), political opinion (political belief or activity), national extraction, social origin, carer and parental status, employment activity, gender activity, lawful sexual activity, industrial activity, physical features, breastfeeding, expunged homosexual activity, personal association, or any other attributes protected by anti-discrimination legislation.</p><p><strong>10.2</strong> Accordingly, in fulfilling their obligations under the Agreement, those covered by the Agreement must make every reasonable endeavour to ensure that neither the Agreement provisions nor their operation are directly or indirectly unlawfully discriminatory in their effects.</p><p><strong>10.3</strong> Nothing in this clause 10 is to be taken to affect:</p><p><strong>(a)</strong> any different treatment (or treatment having different effects) which is specifically exempted under Commonwealth or Victorian anti-discrimination legislation;</p><p><strong>(b)</strong> an Employee, the Employer or registered organisation pursuing matters of discrimination in any State or Federal jurisdiction, including by application to the Australian Human Rights Commission; and</p><p><strong>(c)</strong> the exemptions in section 351(2) of the Act.</p><p><strong>10.4</strong> Gender Based Discrimination</p><p><strong>(a)</strong> The parties agree, in conjunction with the Department, to establish a Gender- Based Standing Committee (GBSC) within three (3) months of the commencement of this Agreement.</p><p><strong>(b)</strong> The purpose of the GBSC will be to:</p><p><strong>(i)</strong> review audit results from audits required by the Gender Equality Act 2020 (Vic);</p><p><strong>(ii)</strong> promote gender equity initiatives; and</p><p><strong>(iii)</strong> identify and address any gender pay gaps in the Victorian Public Health Sector.</p><p><strong>(c)</strong> The GBSC will schedule a minimum of four (4) meetings per year.</p><p><strong>(d)</strong> The GBSC will be comprised of:</p><p><strong>(i)</strong> representatives of the Employers;</p><p><strong>(ii)</strong> the Union; and</p><p><strong>(iii)</strong> the VHIA.</p><p><strong>(e)</strong> The GBSC will:</p><p><strong>(i)</strong> identify any information gaps and develop a framework to address those gaps, which may include additional audit/s; and</p><p><strong>(ii)</strong> develop and implement an action plan to address other gender related issues, such as gendered violence including sexual harassment.</p>',22)])])}const h=e(r,[["render",o]]);export{m as __pageData,h as default};
